<template>
  <div>
    <div class="title">積分商城基礎設置</div>
    <el-card>
      <div style="width: 90%">
        <el-form v-loading="loading" label-width="180px" label-position="left">
          <el-form-item label="入口配置">
            <span class="desc">開啟後，您的用戶能在對應界麵進入積分商城頁面使用積分換購商品。</span>
          </el-form-item>
          <el-form-item>
            <span slot="label">
              移動端 <br>
              (包含小程序/H5/APP）
            </span>
            <el-switch
              v-model="entrance.mobile_openstatus"
              active-color="#13ce66"
              inactive-color="#ff4949"
            />
          </el-form-item>
        </el-form>
      </div>
    </el-card>

    <el-card>
      <div style="width: 70%">
        <el-form v-loading="loading" label-width="180px" :model="form">
          <el-form-item label="物流費用">
            <el-radio-group v-model="form.freight_type">
              <el-radio :label="'cash'"> 按現金 </el-radio>
              <el-radio :label="'point'"> 按積分 </el-radio>
            </el-radio-group>
            <br>
            <span class="tip">說明：運費使用現金或積分支付</span>
          </el-form-item>
          <el-form-item v-if="form.freight_type == 'point'" label="積分商城彙率設置">
            <el-input
              v-model="form.proportion"
              type="number"
              placeholder=""
              style="width: 120px"
              :min="1"
              :max="9999999"
            />積分 抵扣1元台幣
          </el-form-item>
          <el-form-item v-if="form.freight_type == 'point'" label="積分取整設置">
            <el-radio-group v-model="form.rounding_mode">
              <el-radio :label="'down'"> 向下取整 </el-radio>
              <el-radio :label="'up'"> 向上取整 </el-radio>
            </el-radio-group>
            <br>
            <!-- <span class="tip">說明：運費使用現金或積分支付</span> -->
          </el-form-item>
          <!-- <el-form-item size="large">
            <el-button>取消</el-button>
            <el-button type="primary" >儲存</el-button>
          </el-form-item> -->
        </el-form>
      </div>
    </el-card>

    <GlobalFooter>
      <el-button type="primary" @click="save"> 儲存 </el-button>
    </GlobalFooter>
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import { getSetting, saveSetting } from '@/api/pointsmall'
import GlobalFooter from '@/components/global_footer'

export default {
  components: {
    GlobalFooter
  },

  data() {
    return {
      loading: false,
      form: {
        freight_type: 'cash',
        proportion: 0,
        rounding_mode: 'down'
      },
      //移動端是否開啟積分模塊
      entrance: {
        mobile_openstatus: false,
        pc_openstatus: false
      }
    }
  },
  mounted() {
    this.getInfo()
  },
  methods: {
    // 輸入限制小數點兩位
    handleInput2(e) {
      // 通過正則過濾小數點後兩位
      e.target.value = e.target.value.match(/^\d*(\.?\d{0,1})/g)[0] || null
    },
    // 獲取列表
    getInfo() {
      this.loading = true
      getSetting().then((res) => {
        this.form.freight_type = res.data.data.freight_type
        this.form.proportion = res.data.data.proportion
        this.form.rounding_mode = res.data.data.rounding_mode
        this.entrance.mobile_openstatus =
          res.data.data.entrance && res.data.data.entrance.mobile_openstatus
            ? res.data.data.entrance.mobile_openstatus
            : false
        this.loading = false
      })
    },
    // 儲存數據
    save() {
      saveSetting({
        ...this.form,
        entrance: {
          mobile_openstatus: this.entrance.mobile_openstatus
        }
      }).then((res) => {
        this.$message({ type: 'success', message: '操作成功' })
        this.getInfo()
      })
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  }
}
</script>
